// src/pages/RegisterManageSub1Page.js
import React, { useEffect, useState, useCallback } from 'react';
import axios from 'axios';
import { useNavigate } from 'react-router-dom';
import * as XLSX from 'xlsx';

import './RegisterManageSub1Page.css';

// Component DebouncedInput để tránh gọi API liên tục khi gõ tìm kiếm
const DebouncedInput = ({ value, onChange, ...props }) => {
  const [internalValue, setInternalValue] = useState(value);

  useEffect(() => {
    const handler = setTimeout(() => {
      onChange(internalValue);
    }, 500); // Đợi 500ms sau khi người dùng ngừng gõ

    return () => clearTimeout(handler);
  }, [internalValue, onChange]);

  useEffect(() => {
    setInternalValue(value);
  }, [value]);

  return <input {...props} value={internalValue} onChange={e => setInternalValue(e.target.value)} />;
};

function RegisterManageSub1Page() {
  // State cho dữ liệu và trạng thái UI
  const [woods, setWoods] = useState([]);
  const [loading, setLoading] = useState(false);
  const [error, setError] = useState(null);

  // State cho các bộ lọc
  const [filter, setFilter] = useState('');
  const [selectedProvince, setSelectedProvince] = useState('');
  const [selectedCommune, setSelectedCommune] = useState('');
  const [selectedNganhNgheKinhDoanhGo, setSelectedNganhNgheKinhDoanhGo] = useState('');
  const [selectedTrangThai, setSelectedTrangThai] = useState('');
  const [selectedLoaiHinhCheBienGo, setSelectedLoaiHinhCheBienGo] = useState('');
  const [selectedNguonGocGo, setSelectedNguonGocGo] = useState('');

  // State cho phân trang
  const [currentPage, setCurrentPage] = useState(1);
  const [totalPages, setTotalPages] = useState(1);
  const [itemsPerPage, setItemsPerPage] = useState(15);

  // State cho cấu hình cột
  const [columns, setColumns] = useState({}); // Khởi tạo rỗng, sẽ được load từ localStorage
  const [showColumnOptions, setShowColumnOptions] = useState(false);

  const navigate = useNavigate();
  const token = localStorage.getItem('token');

  // Cấu hình cột ban đầu
  const initialColumnsConfig = {
    // ... Dán toàn bộ object initialColumnsConfig của bạn vào đây ...
    // Ví dụ:
    tinhThanhPho: { id: 'tinhThanhPho', label: 'Tỉnh (TP)', visible: true, minWidth: '100px' },
    xaPhuong: { id: 'xaPhuong', label: 'Xã (Phường)', visible: true, minWidth: '100px' },
    diaChiCoSo: { id: 'diaChiCoSo', label: 'Địa chỉ cơ sở', visible: true, minWidth: '220px' },
    tenCoSo: { id: 'tenCoSo', label: 'Tên cơ sở', visible: true, minWidth: '180px' },
    // Thêm tất cả các cột khác của bạn ở đây...
    loaiHinhCheBienGo: { id: 'loaiHinhCheBienGo', label: 'Loại hình chế biến', visible: false, minWidth: '120px' },
    nguonGocGo: { id: 'nguonGocGo', label: 'Nguồn gốc gỗ', visible: false, minWidth: '120px' },
    actions: { id: 'actions', label: '🛠️', visible: true, width: '175px', minWidth: '175px', maxWidth: '175px' },
  };

  // useEffect để load cấu hình cột từ localStorage
  useEffect(() => {
    try {
      const savedColumns = localStorage.getItem('tableColumnsVisibility_WoodBusiness');
      if (savedColumns) {
        setColumns(JSON.parse(savedColumns));
      } else {
        setColumns(initialColumnsConfig);
      }
    } catch (error) {
      console.error("Lỗi khi tải cấu hình cột:", error);
      setColumns(initialColumnsConfig);
    }
  }, []); // Chỉ chạy một lần khi component mount

  // Hàm fetch dữ liệu chính, giao tiếp với backend
  const fetchWoodBusinesses = useCallback(async () => {
    setLoading(true);
    setError(null);
    if (!token) {
      navigate('/');
      return;
    }

    try {
      const params = {
        page: currentPage,
        limit: itemsPerPage,
        farmType: 'Đăng ký cơ sở kinh doanh, chế biến gỗ',
        search: filter,
        tinhThanhPho: selectedProvince,
        xaPhuong: selectedCommune,
        trangThai: selectedTrangThai,
        nganhNgheKinhDoanhGo: selectedNganhNgheKinhDoanhGo,
        loaiHinhCheBienGo: selectedLoaiHinhCheBienGo,
        nguonGocGo: selectedNguonGocGo,
      };

      Object.keys(params).forEach(key => (params[key] === '' || params[key] === null) && delete params[key]);

      const response = await axios.get('http://localhost:10000/api/farms', {
        headers: { Authorization: `Bearer ${token}` },
        params
      });

      setWoods(response.data.docs || []);
      setTotalPages(response.data.totalPages || 1);
    } catch (err) {
      console.error('Lỗi khi lấy danh sách:', err);
      setError('Không thể tải dữ liệu.');
      setWoods([]);
    } finally {
      setLoading(false);
    }
  }, [token, currentPage, itemsPerPage, filter, selectedProvince, selectedCommune, selectedTrangThai, selectedNganhNgheKinhDoanhGo, selectedLoaiHinhCheBienGo, selectedNguonGocGo, navigate]);

  useEffect(() => {
    fetchWoodBusinesses();
  }, [fetchWoodBusinesses]);

  // Hàm xử lý khi thay đổi bộ lọc hoặc tìm kiếm
  const handleFilterChange = (setter) => (e) => {
    setter(e.target.value);
    setCurrentPage(1); // Reset về trang 1 khi áp dụng bộ lọc mới
  };

  // Các hàm xử lý khác (delete, edit, export...)
  const handleDelete = async (id) => { /* ... giữ nguyên logic ... */ };
  const handleEdit = (id) => { /* ... giữ nguyên logic ... */ };
  const handleNavigateToWoodDetail = (id) => navigate(`/admin/woods/${id}`);

  // JSX để hiển thị
  return (
    <div className="farm-list-container">
      <h2>📋 Danh sách cơ sở kinh doanh, chế biến gỗ</h2>

      <div className="filter-container">
        <DebouncedInput
          placeholder="🔍 Tìm kiếm chung..."
          value={filter}
          onChange={(value) => {
            setFilter(value);
            setCurrentPage(1);
          }}
        />
        <select value={selectedProvince} onChange={handleFilterChange(setSelectedProvince)}>
          <option value="">Tất cả Tỉnh (TP)</option>
          {/* Bạn có thể fetch danh sách tỉnh riêng hoặc để trống */}
        </select>
        {/* Thêm các dropdown filter khác tương tự */}
      </div>

      {/* Nút quản lý cột */}
      <button onClick={() => setShowColumnOptions(!showColumnOptions)}>Hiện, ẩn cột</button>
      {/* ... code cho phần chọn cột ... */}

      {loading && <p>Đang tải dữ liệu...</p>}
      {error && <p className="error-message">{error}</p>}

      {!loading && !error && (
        <>
          <div className="table-responsive">
            {woods.length > 0 ? (
              <table className="table-auto w-full border-collapse">
                {/* a... a... a... */}
                <tbody>
                  {woods.map((item) => (
                    <tr key={item._id}>
                      {/* ... render các cột động dựa trên state `columns` ... */}
                    </tr>
                  ))}
                </tbody>
              </table>
            ) : (
              <p>Không tìm thấy cơ sở nào phù hợp.</p>
            )}
          </div>

          <div className="pagination-container">
            <button onClick={() => setCurrentPage(currentPage - 1)} disabled={currentPage <= 1}>«</button>
            <span>Trang {currentPage} / {totalPages}</span>
            <button onClick={() => setCurrentPage(currentPage + 1)} disabled={currentPage >= totalPages}>»</button>
          </div>
        </>
      )}
    </div>
  );
}

export default RegisterManageSub1Page;
